example.code:
IAppControls appControls = Comos.Global.AppGlobal.AppControls;
IAppControlOptions options = appControls.CreateOptions();

options.Assembly = "CommonComosTests";
options.Class = "CommonComosTests.MyUserControl";
// or:
// options.ToolId = "MyToolId";

IAppControlAppearance appearance = options.Appearance;

appearance.Area = Area.Navigator;
appearance.SubArea = SubArea.Detail;

IAppControl appControl = appControls.Create(options);

if (appControl != null)
{
    IAppControlHeader header = appControl.Header;

    header.Title = "MyTitle";
    header.Image = Comos.PicturesLibrary.Pictures.Instance.PictureByKey("std_actionWarning");

    appControl.Show();
}

IAppControls appControls = Comos.Global.AppGlobal.AppControls;
IAppControl appControl = null;

for (int i = 0; i < appControls.Count; i++)
{
    if (appControls[i].Control is MyUserControl)
    {
        appControl = appControls[i];
        break;
    }
}

if (appControl != null)
    appControls.TryClose(appControl);

